// n8n Code Node - Extract Contact Data from Apollo Bulk Enrichment Response

const items = $input.all();
const extractedContacts = [];

for (const item of items) {
  const data = item.json;

  // Check if matches array exists
  const matches = data.matches || [];

  matches.forEach(person => {
    extractedContacts.push({
      json: {
        // Basic identification
        id: person.id || '',
        first_name: person.first_name || '',
        last_name: person.last_name || '',
        name: person.name || '',

        // Contact information
        email: person.email || '',
        email_status: person.email_status || '',
        phone: person.organization?.phone || person.organization?.primary_phone?.number || '',
        linkedin_url: person.linkedin_url || '',

        // Professional information
        title: person.title || '',
        position: person.title || '', // Same as title
        headline: person.headline || '',
        seniority: person.seniority || '',

        // Company/Organization information
        company_name: person.organization?.name || '',
        organization_id: person.organization_id || '',
        organization_website: person.organization?.website_url || '',
        organization_phone: person.organization?.phone || '',
        organization_domain: person.organization?.primary_domain || '',
        organization_industry: person.organization?.industry || '',
        organization_employees: person.organization?.estimated_num_employees || '',
        organization_revenue: person.organization?.organization_revenue_printed || '',

        // Location information
        city: person.city || '',
        state: person.state || '',
        country: person.country || '',
        formatted_address: person.formatted_address || '',

        // Additional useful fields
        photo_url: person.photo_url || '',
        personal_emails: (person.personal_emails || []).join('; '),
        departments: (person.departments || []).join('; '),
        subdepartments: (person.subdepartments || []).join('; '),
        functions: (person.functions || []).join('; '),

        // Current employment
        current_company: person.employment_history?.[0]?.organization_name || '',
        current_title: person.employment_history?.[0]?.title || '',
        current_start_date: person.employment_history?.[0]?.start_date || '',
      }
    });
  });
}

return extractedContacts;

// Prepare data for Reoon Bulk Verification
const items = $input.all();

// Collect all emails into an array
const emails = items
  .map(item => item.json.email)
  .filter(email => email && email !== '' && email !== '<REDACTED_EMAIL>');

// Return single item with the array
return [{
  json: {
    name: `k ${new Date().toISOString()}`,
    emails: emails,  // This is an array
    key: "<REOON_API_KEY>"  // Replace with your actual API key
  }
}];

// Pass only verified (valid / catch_all / safe) emails
// n8n Code Node

// Allowed email statuses
const allowedStatuses = ['valid', 'catch_all', 'verified', 'safe'];
const allowedOuterStatuses = ['running', 'completed'];

// 1. Extract people items (with emails and email_status)
const prospectItems = items.filter(
  item => item.json && typeof item.json.email === 'string' && item.json.email_status
);

// 2. Extract verification results items (from Reoon API response)
// Check outer status is 'running' or 'completed'
const verifyItems = items.filter(
  item =>
    item.json &&
    typeof item.json.results === 'object' &&
    allowedOuterStatuses.includes(item.json.status)
);

// 3. Create a Set of emails marked as valid, catch_all, verified, or safe
const allowedEmails = new Set();

// Add emails from Reoon verification results
// Check inner status within results object
verifyItems.forEach(item => {
  const results = item.json.results || {};
  Object.entries(results).forEach(([email, result]) => {
    if (
      result &&
      result.status &&
      allowedStatuses.includes(result.status)
    ) {
      allowedEmails.add(email.toLowerCase().trim());
    }
  });
});

// 4. Filter people to include only those with allowed emails
// Check BOTH: email in allowedEmails Set OR email_status in allowedStatuses
const filteredOutput = prospectItems
  .filter(item => {
    const email = item.json.email.toLowerCase().trim();
    const emailStatus = item.json.email_status;

    // Pass if email is in verified set OR if email_status is allowed
    return allowedEmails.has(email) || allowedStatuses.includes(emailStatus);
  })
  .map(item => ({ json: item.json }));

// 5. Return filtered leads
return filteredOutput;

// n8n Code node — limit to <= 3 leads per organization_domain, keep full records, dedupe

const MAX_PER_DOMAIN = 3;

const items = $input.all();

// Normalize a domain-ish string (strip protocol, trailing paths, leading www)
function normalizeDomain(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (!s) return '';
  // strip protocol
  let d = s.replace(/^https?:\/\//, '');
  // take until first slash
  d = d.split('/')[0];
  // strip leading www.
  d = d.replace(/^www\./, '');
  return d;
}

// Stable dedupe key for a person/lead
function dedupeKey(j) {
  if (j.id) return `id:${String(j.id)}`;
  const email = String(j.email || '').toLowerCase().trim();
  const li = String(j.linkedin_url || '').toLowerCase().trim();
  const name = String(j.name || '').toLowerCase().trim();
  const orgId = String(j.organization_id || '').toLowerCase().trim();
  const title = String(j.current_title || j.title || '').toLowerCase().trim();
  const orgDomain = normalizeDomain(j.organization_domain);
  return `k:${email}|${li}|${name}|${orgId}|${title}|${orgDomain}`;
}

const seenPerDomain = new Map(); // domain -> Set(keys)
const keptCount = new Map();     // domain -> number kept
const out = [];

for (const item of items) {
  const j = item.json || {};
  const domain = normalizeDomain(j.organization_domain);

  // skip if no domain (change to include if you prefer: just remove this continue)
  if (!domain) continue;

  // init maps
  if (!seenPerDomain.has(domain)) seenPerDomain.set(domain, new Set());
  if (!keptCount.has(domain)) keptCount.set(domain, 0);

  // enforce max per domain
  if (keptCount.get(domain) >= MAX_PER_DOMAIN) continue;

  // dedupe within domain
  const key = dedupeKey(j);
  const seenSet = seenPerDomain.get(domain);
  if (seenSet.has(key)) continue;

  seenSet.add(key);
  keptCount.set(domain, keptCount.get(domain) + 1);

  // keep full original record
  out.push({ json: j });
}

return out;

// This code goes into an n8n "Code" node.
// It assumes the input is a list of detailed person objects like you provided.

// 1. Get all the incoming items (the list of people).
const items = $input.all();

// 2. Use .map() to transform each person object into the required format.
const formattedDetails = items.map(item => {
  const person = item.json;

  // Create a new, smaller object with only the fields Apollo needs for matching.
  // We include several fields to improve the match accuracy.
  return {
    first_name: person.first_name,
    last_name: person.last_name,
    linkedin_url: person.linkedin_url,
    organization_domain: person.organization_domain,
    title: person.title,
    id: person.id
  };
});

// 3. Create the final request body object, which has a single key "details".
const requestBody = {
  details: formattedDetails
};

// 4. Return the result as a single item.
// The next node (HTTP Request) will use this output as its body.
return [{
  json: {
    // We name the output 'body' for easy reference in the HTTP Request node.
    body: requestBody
  }
}];

// n8n Function Node

const data = $input.item.json;

// If model_ids is empty or missing, output special message
if (!Array.isArray(data.model_ids) || data.model_ids.length === 0) {
  return [{ json: { message: "No leads found." } }];
}

// Extract people array (compatible with variations in data)
const people = Array.isArray(data)
  ? data[0]?.people || []
  : data.people || [];

// Map and extract all contact details
const extractedContacts = people.map(person => ({
  // Basic identification
  id: person.id || '',
  first_name: person.first_name || '',
  last_name: person.last_name || '',
  name: person.name || '',

  // Contact information
  email: person.email || '',
  email_status: person.email_status || '',
  linkedin_url: person.linkedin_url || '',
  twitter_url: person.twitter_url || '',
  github_url: person.github_url || '',
  facebook_url: person.facebook_url || '',

  // Professional information
  title: person.title || '',
  headline: person.headline || '',
  seniority: person.seniority || '',

  // Location information
  city: person.city || '',
  state: person.state || '',
  country: person.country || '',
  postal_code: person.postal_code || '',
  formatted_address: person.formatted_address || '',
  time_zone: person.time_zone || '',

  // Organization information
  organization_id: person.organization_id || '',
  organization_name: person.organization?.name || '',
  organization_website: person.organization?.website_url || '',
  organization_phone: person.organization?.phone || '',
  organization_linkedin: person.organization?.linkedin_url || '',
  organization_domain: person.organization?.primary_domain || '',
  organization_founded_year: person.organization?.founded_year || '',

  // Additional fields
  photo_url: person.photo_url || '',
  departments: (person.departments || []).join('; '),
  subdepartments: (person.subdepartments || []).join('; '),
  functions: (person.functions || []).join('; '),
  email_domain_catchall: person.email_domain_catchall || false,

  // Employment history (current position)
  current_company: person.employment_history?.[0]?.organization_name || '',
  current_title: person.employment_history?.[0]?.title || '',
  current_start_date: person.employment_history?.[0]?.start_date || '',
  is_current_role: person.employment_history?.[0]?.current || false,
}));

// Return extracted contacts or message
return extractedContacts.length
  ? extractedContacts.map(contact => ({ json: contact }))
  : [{ json: { message: "No leads found." } }];

// n8n Code node — Build Apollo Mixed People Search POST body
// Simplified version - Companies already filtered by ICP

// 1) Inputs
const items = $input.all();

// 2) Extract valid domains and Apollo IDs from scored companies
const companies = items.map(item => {
  const data = item.json;

  // Clean and extract domain
  let domain = String(data.Website || data.domain || '').trim();
  domain = domain
    .replace(/^https?:\/\/(www\.)?/, '')
    .replace(/\/$/, '')
    .toLowerCase();

  // Extract Apollo Account ID

  return {
    domain: domain,
    companyName: data['Company Name'] || data.companyName || ''
  };
}).filter(c => 
  c.domain && 
  c.domain !== 'not found' && 
  c.domain.includes('.')
);

// Remove duplicates
const uniqueDomains = [...new Set(companies.map(c => c.domain))];


// Guard
if (uniqueDomains.length === 0) {
  return [{ json: { error: 'No valid domains found in input data' } }];
}

// 3) Target Titles - Founders & C-Suite only
const titles = [
  // Founders
  'Founder',
  'Co-Founder',
  'Co Founder',
  'Cofounder',
  'Founding Partner',

  // C-Suite
  'CEO',
  'Chief Executive Officer',
  'CFO',
  'Chief Financial Officer',
  'COO',
  'Chief Operating Officer',
  'CTO',
  'Chief Technology Officer',
  'CMO',
  'Chief Marketing Officer',
  'CRO',
  'Chief Revenue Officer',
  'CIO',
  'Chief Information Officer',
  'CPO',
  'Chief Product Officer',

  // Sales Leadership
  'Head of Sales',
  'VP Sales',
  'Vice President of Sales',
  'VP of Sales',
  'SVP Sales',

  // Other Key Executives
  'President',
  'Managing Director',
  'Owner'
];

// 4) Build simplified POST body for mixed_people/search
const body = {
  // Person filters - ONLY targeting founders & C-suite
  person_titles: titles,
  person_seniorities: ['founder', 'c_suite', 'owner'],

  // Domain filter (primary identifier)
  q_organization_domains: uniqueDomains,

  // Pagination
  page: 1,
  per_page: 100
};

// Add Apollo IDs if available (helps with accuracy)

// 5) Output for HTTP Request node
return [{
  json: {
    url: 'https://api.apollo.io/api/v1/mixed_people/search',
    method: 'POST',
    body: body,
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'no-cache'
    },
    // Metadata for logging
    metadata: {
      processedCompanies: companies.length,
      uniqueDomains: uniqueDomains.length,
      sampleDomains: uniqueDomains.slice(0, 5),
    }
  }
}];

const items = $('Get row(s) in sheet').all().map(item => {
  const website = String(item.json.Website).trim();
  const domain = website
    .replace(/^https?:\/\/(www\.)?/, '')
    .replace(/\/$/, '')
    .toLowerCase();
  return { json: { website: domain } };
});
return items;

// Extract first_name, last_name, id, and title from Apollo response
const inputData = $input.first().json;

// Check if we have people array in the response
if (!inputData.people || !Array.isArray(inputData.people) || inputData.people.length === 0) {
  return [{ json: { message: "No leads found.", contacts: [] } }];
}

// Map through people array and extract required fields
const contacts = inputData.people.map(person => ({
  first_name: person.first_name || '',
  last_name: person.last_name_obfuscated || '',
  id: person.id || '',
  title: person.title || ''
}));

// Return all contacts in a single JSON object
return [{ json: { contacts: contacts, total_count: contacts.length } }];

